// Binding different value types
void AMyChar::SetupPlayerInputComponent(UInputComponent* PIC) {
    UEnhancedInputComponent* EIC = Cast<UEnhancedInputComponent>(PIC);

    // Bool action (jump)
    EIC->BindAction(JumpAction, ETriggerEvent::Started, this, &AMyChar::OnJump);

    // Axis2D action (movement)
    EIC->BindAction(MoveAction, ETriggerEvent::Triggered, this, &AMyChar::OnMove);
}

void AMyChar::OnJump(const FInputActionValue& Value) {
    bool bPressed = Value.Get<bool>();
    Jump();
}

void AMyChar::OnMove(const FInputActionValue& Value) {
    FVector2D Axis = Value.Get<FVector2D>();
    AddMovementInput(GetActorForwardVector(), Axis.Y);
    AddMovementInput(GetActorRightVector(), Axis.X);
}

// Adding and swapping mapping contexts
void AMyChar::BeginPlay() {
    if (auto* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer())) {
        Subsystem->AddMappingContext(OnFootContext, 0);  // priority 0
    }
}

void AMyChar::EnterVehicle() {
    if (auto* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer())) {
        Subsystem->RemoveMappingContext(OnFootContext);
        Subsystem->AddMappingContext(VehicleContext, 0);
    }
}

// Trigger events and their meanings:
// ETriggerEvent::Started    — first frame the trigger condition begins activating
// ETriggerEvent::Ongoing    — trigger is still being evaluated (e.g., during hold buildup)
// ETriggerEvent::Triggered  — the trigger condition is fully met (the main event)
// ETriggerEvent::Completed  — the trigger finished successfully (e.g., key released after hold)
// ETriggerEvent::Canceled   — the trigger was interrupted before completing

// Example: bind to Triggered for the main action
EIC->BindAction(FireAction, ETriggerEvent::Triggered, this, &AMyChar::OnFire);

// Example: hold action — Started when hold begins, Triggered when hold completes
EIC->BindAction(ChargeAction, ETriggerEvent::Started, this, &AMyChar::OnChargeStart);
EIC->BindAction(ChargeAction, ETriggerEvent::Triggered, this, &AMyChar::OnChargeComplete);
